export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult<T extends Record<string, unknown> = Record<string, unknown>> {
  rows: T[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: T, index: number) => boolean): T[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, T[]>;
}

interface ParsedData {
  rows: string[][];
  errors: CSVError[];
}

const DEFAULT_DELIMITER = ",";
const DEFAULT_QUOTE = "\"";

const numberPattern = /^-?\d+(\.\d+)?$/;

function coerceValue(value: string): unknown {
  if (value === "") {
    return null;
  }
  const lowered = value.toLowerCase();
  if (lowered === "null") {
    return null;
  }
  if (lowered === "true") {
    return true;
  }
  if (lowered === "false") {
    return false;
  }
  if (numberPattern.test(value)) {
    const num = Number(value);
    if (!Number.isNaN(num) && Number.isFinite(num)) {
      return num;
    }
  }
  return value;
}

function parseRawRows(input: string, options: CSVOptions): ParsedData {
  const delimiter = options.delimiter ?? DEFAULT_DELIMITER;
  const quoteChar = options.quoteChar ?? DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator;
  const rows: string[][] = [];
  const errors: CSVError[] = [];

  let currentField = "";
  let currentRow: string[] = [];
  let inQuotes = false;
  let rowNumber = 1;
  let i = 0;

  const pushField = () => {
    currentRow.push(currentField);
    currentField = "";
  };

  const pushRow = () => {
    rows.push(currentRow);
    currentRow = [];
    rowNumber += 1;
  };

  const consumeLineSeparator = (): number => {
    if (lineSeparator) {
      if (input.startsWith(lineSeparator, i)) {
        return lineSeparator.length;
      }
      return 0;
    }
    const char = input[i];
    if (char === "\r" && input[i + 1] === "\n") {
      return 2;
    }
    if (char === "\n" || char === "\r") {
      return 1;
    }
    return 0;
  };

  while (i < input.length) {
    const char = input[i];

    if (inQuotes) {
      if (char === quoteChar) {
        if (input[i + 1] === quoteChar) {
          currentField += quoteChar;
          i += 2;
          continue;
        }
        inQuotes = false;
        i += 1;
        continue;
      }
      currentField += char;
      i += 1;
      continue;
    }

    if (char === quoteChar) {
      inQuotes = true;
      i += 1;
      continue;
    }

    if (char === delimiter) {
      pushField();
      i += 1;
      continue;
    }

    const lineSepLength = consumeLineSeparator();
    if (lineSepLength > 0) {
      pushField();
      pushRow();
      i += lineSepLength;
      continue;
    }

    currentField += char;
    i += 1;
  }

  if (inQuotes) {
    errors.push({
      row: rowNumber,
      message: "Unclosed quoted field.",
    });
  }

  const shouldPushLastRow =
    currentRow.length > 0 ||
    currentField !== "" ||
    (input.length > 0 &&
      (input.endsWith(delimiter) ||
        (lineSeparator && input.endsWith(lineSeparator)) ||
        (!lineSeparator && (input.endsWith("\n") || input.endsWith("\r")))));

  if (shouldPushLastRow) {
    pushField();
    rows.push(currentRow);
  }

  return { rows, errors };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  if (!input) {
    return {
      rows: [],
      headers: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const { rows: rawRows, errors } = parseRawRows(input, options);

  if (rawRows.length === 0) {
    return {
      rows: [],
      headers: [],
      errors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const headers = rawRows[0].map((header) => header);
  const rows = rawRows.slice(1).map((rawRow, index) => {
    if (rawRow.length !== headers.length) {
      errors.push({
        row: index + 2,
        message: `Row has ${rawRow.length} columns but expected ${headers.length}.`,
      });
    }

    const record: Record<string, unknown> = {};
    headers.forEach((header, headerIndex) => {
      const value = rawRow[headerIndex] ?? "";
      record[header] = coerceValue(value);
    });
    return record;
  });

  const result: CSVResult = {
    rows,
    headers,
    errors,
    filter: (predicate) => rows.filter(predicate),
    sum: (column) =>
      rows.reduce((total, row) => {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          return total + value;
        }
        return total;
      }, 0),
    average: (column) => {
      let total = 0;
      let count = 0;
      rows.forEach((row) => {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      });
      return count === 0 ? 0 : total / count;
    },
    count: () => rows.length,
    groupBy: (column) => {
      const map = new Map<unknown, Record<string, unknown>[]>();
      rows.forEach((row) => {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)?.push(row);
      });
      return map;
    },
  };

  return result;
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function deepEqual(actual: unknown, expected: unknown, message: string) {
  const normalize = (value: unknown): unknown => {
    if (Array.isArray(value)) {
      return value.map(normalize);
    }
    if (value && typeof value === "object") {
      return Object.keys(value as Record<string, unknown>)
        .sort()
        .reduce<Record<string, unknown>>((acc, key) => {
          acc[key] = normalize((value as Record<string, unknown>)[key]);
          return acc;
        }, {});
    }
    return value;
  };

  const actualNormalized = JSON.stringify(normalize(actual));
  const expectedNormalized = JSON.stringify(normalize(expected));

  if (actualNormalized !== expectedNormalized) {
    throw new Error(
      `${message}\nExpected: ${expectedNormalized}\nReceived: ${actualNormalized}`
    );
  }
}

function runTests() {
  {
    const input = "name,age\nAlice,30\nBob,25";
    const result = parseCSV(input);
    deepEqual(result.headers, ["name", "age"], "Basic headers");
    deepEqual(result.rows, [
      { name: "Alice", age: 30 },
      { name: "Bob", age: 25 },
    ], "Basic rows");
    assert(result.errors.length === 0, "Basic parsing errors should be empty");
  }

  {
    const input = "name,notes\nAlice,\"hello, world\"\nBob,\"a,b,c\"";
    const result = parseCSV(input);
    deepEqual(result.rows[0], { name: "Alice", notes: "hello, world" }, "Quoted field with comma");
    deepEqual(result.rows[1], { name: "Bob", notes: "a,b,c" }, "Quoted field with commas");
  }

  {
    const input = "name,quote\nAlice,\"She said \"\"hi\"\"\"";
    const result = parseCSV(input);
    deepEqual(result.rows[0], { name: "Alice", quote: "She said \"hi\"" }, "Escaped quotes");
  }

  {
    const input = "name;age|Alice;30|Bob;40";
    const result = parseCSV(input, {
      delimiter: ";",
      quoteChar: "'",
      lineSeparator: "|",
    });
    deepEqual(result.rows, [
      { name: "Alice", age: 30 },
      { name: "Bob", age: 40 },
    ], "Custom delimiter parsing");
  }

  {
    const input = "n,b,bool1,bool2,empty,nullval,string\n1,2.5,true,FALSE,,NULL,hello";
    const result = parseCSV(input);
    deepEqual(result.rows[0], {
      n: 1,
      b: 2.5,
      bool1: true,
      bool2: false,
      empty: null,
      nullval: null,
      string: "hello",
    }, "Type coercion");
  }

  {
    const input = "col1,col2\n1,2,3\n4";
    const result = parseCSV(input);
    assert(result.errors.length === 2, "Malformed rows should collect errors");
    deepEqual(result.rows[0], { col1: 1, col2: 2 }, "Malformed row extra column still parsed");
    deepEqual(result.rows[1], { col1: 4, col2: null }, "Malformed row missing column should be null");
  }

  {
    const input = "name,score\nAlice,90\nBob,70\nCara,85";
    const result = parseCSV(input);
    const filtered = result.filter((row) => (row.score as number) >= 85);
    deepEqual(filtered, [
      { name: "Alice", score: 90 },
      { name: "Cara", score: 85 },
    ], "Filter rows");
  }

  {
    const input = "category,value\nA,10\nA,20\nB,5";
    const result = parseCSV(input);
    assert(result.count() === 3, "Count rows");
    assert(result.sum("value") === 35, "Sum values");
    assert(result.average("value") === 35 / 3, "Average values");
    const grouped = result.groupBy("category");
    assert(grouped.get("A")?.length === 2, "GroupBy A count");
    assert(grouped.get("B")?.length === 1, "GroupBy B count");
  }

  {
    const result = parseCSV("");
    deepEqual(result.headers, [], "Empty input headers");
    deepEqual(result.rows, [], "Empty input rows");
    assert(result.errors.length === 0, "Empty input errors");
  }

  {
    const input = "value\n1\n2";
    const result = parseCSV(input);
    deepEqual(result.headers, ["value"], "Single column headers");
    deepEqual(result.rows, [{ value: 1 }, { value: 2 }], "Single column rows");
  }

  {
    const input = "a,b\n1,2";
    const result = parseCSV(input);
    deepEqual(result.rows, [{ a: 1, b: 2 }], "Single row parsing");
  }

  {
    const largeField = "x".repeat(10000);
    const input = `data\n\"${largeField}\"`;
    const result = parseCSV(input);
    deepEqual(result.rows, [{ data: largeField }], "Very large field parsing");
  }
}

runTests();
console.log("All tests passed.");

